const body = $json.body ?? $json;

const clean = (value) => String(value ?? '').trim();
const cleanEmail = (value) => clean(value).toLowerCase();
const now = new Date().toISOString();
const archiveFileName = `${now.replace(/[:.]/g, '-').slice(0, 19)}-hsb-boden-lead.md`;

const lead = {
  receivedAt: now,
  source: clean(body.source),
  legalBasis: clean(body.legalBasis),
  firstName: clean(body.firstName),
  lastName: clean(body.lastName),
  fullName: `${clean(body.firstName)} ${clean(body.lastName)}`.trim(),
  company: clean(body.company),
  email: cleanEmail(body.email),
  phone: clean(body.phone),
  industry: clean(body.industry),
  projectType: clean(body.projectType),
  areaSize: clean(body.areaSize),
  liveOperation: clean(body.liveOperation),
  loads: clean(body.loads),
  message: clean(body.message),
  privacyConsent: body.privacyConsent === true,
  access_key_present: Boolean(clean(body.access_key))
};

const errors = [];

if (!lead.firstName) errors.push('missing_firstName');
if (!lead.lastName) errors.push('missing_lastName');
if (!lead.email || !lead.email.includes('@')) errors.push('invalid_email');
if (lead.privacyConsent !== true) errors.push('privacyConsent_not_true');
if (!lead.source) errors.push('missing_source');
if (!lead.legalBasis) errors.push('missing_legalBasis');

const esc = (value) => String(value ?? '').replace(/\r?\n/g, ' ').replace(/"/g, '\"');
const rawJson = JSON.stringify(body, null, 2);

const archiveContent = `---
receivedAt: "${esc(lead.receivedAt)}"
source: "${esc(lead.source)}"
legalBasis: "${esc(lead.legalBasis)}"
fullName: "${esc(lead.fullName)}"
company: "${esc(lead.company)}"
email: "${esc(lead.email)}"
phone: "${esc(lead.phone)}"
industry: "${esc(lead.industry)}"
projectType: "${esc(lead.projectType)}"
areaSize: "${esc(lead.areaSize)}"
liveOperation: "${esc(lead.liveOperation)}"
privacyConsent: ${lead.privacyConsent}
---

# Nachricht
${lead.message || '_Keine Nachricht angegeben._'}

# Belastungen
${lead.loads || '_Keine Belastungen angegeben._'}

# Rohdaten
\`\`\`json
${rawJson}
\`\`\`
`;

const emailBody = `Neue Projektanfrage über hsb-boden.de

Eingang: ${lead.receivedAt}
Name: ${lead.fullName}
Firma: ${lead.company}
E-Mail: ${lead.email}
Telefon: ${lead.phone}
Branche: ${lead.industry}
Projektart: ${lead.projectType}
Fläche: ${lead.areaSize}
Sanierung im laufenden Betrieb: ${lead.liveOperation}
Belastungen: ${lead.loads}

Nachricht:
${lead.message}

Quelle: ${lead.source}
Rechtsgrundlage: ${lead.legalBasis}
Datenschutz-Einwilligung: ${lead.privacyConsent}
Access-Key vorhanden: ${lead.access_key_present}
`;

return {
  json: {
    ok: errors.length === 0,
    errors,
    lead,
    archiveFileName,
    archiveContent,
    emailSubject: 'Neue Projektanfrage über hsb-boden.de',
    emailBody
  }
};
